import statistics
from typing import List

def calibrate_linear(monthly_tokens: List[float]) -> dict:
    """Estimate linear growth parameters from historical monthly volumes."""
    if len(monthly_tokens) < 2:
        raise ValueError("Need at least 2 months of data for linear calibration.")
    increments = [monthly_tokens[i] - monthly_tokens[i-1]
                  for i in range(1, len(monthly_tokens))]
    return {
        "base_tokens": monthly_tokens[-1],
        "monthly_increment": statistics.mean(increments),
        "increment_stdev": statistics.stdev(increments) if len(increments) > 1 else 0,
    }

def calibrate_compound(monthly_tokens: List[float]) -> dict:
    """Estimate compound growth rate from historical monthly volumes."""
    if len(monthly_tokens) < 2:
        raise ValueError("Need at least 2 months of data for compound calibration.")
    growth_rates = [
        (monthly_tokens[i] / monthly_tokens[i-1]) - 1
        for i in range(1, len(monthly_tokens))
    ]
    return {
        "base_tokens": monthly_tokens[-1],
        "monthly_growth_rate": statistics.mean(growth_rates),
        "rate_stdev": statistics.stdev(growth_rates) if len(growth_rates) > 1 else 0,
    }

# Example
history = [18_000_000, 21_600_000, 24_800_000, 28_200_000, 33_000_000]
print("Linear params:", calibrate_linear(history))
print("Compound params:", calibrate_compound(history))
